#!/usr/bin/env node
// patch-jejo-refine.cjs — Bouton + rond en bas centre, orientation portrait/paysage,
// musique par d\u00e9faut variable (artiste r\u00e9cent/populaire), filtres Lissage/Beaut\u00e9,
// liste musique = artistes uniquement (Jejo + Story).

const fs = require('fs');
const path = require('path');
const ROOT = process.cwd();
let ok = 0, fail = 0;
const good = m => { console.log('  \u2705 ' + m); ok++; };
const skip = m => { console.log('  \u26a0\ufe0f  ' + m); };
const err  = m => { console.log('  \u274c ' + m); fail++; };
const read = rel => { const p = path.join(ROOT, rel); return fs.existsSync(p) ? fs.readFileSync(p, 'utf8') : null; };
const write = (rel, s) => fs.writeFileSync(path.join(ROOT, rel), s, 'utf8');
function rep(rel, from, to, label) {
  const s = read(rel); if (s == null) { err('Introuvable: ' + rel); return; }
  if (s.includes(to)) { good(label + ' (déjà appliqué)'); return; }
  if (!s.includes(from)) { skip('Ancre manquante: ' + label); return; }
  write(rel, s.replace(from, to)); good(label);
}

console.log('\n\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550');
console.log('  PATCH \u2014 Jejo/Story raffinements');
console.log('\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n');

// [1] R\u00e9\u00e9crire les composants (musique artiste par d\u00e9faut, orientation, filtres beaut\u00e9)
console.log('[1] Composants...');
try { fs.writeFileSync(path.join(ROOT,'src/components/StoryStudio.jsx'), Buffer.from('','base64').toString('utf8'),'utf8'); good('StoryStudio.jsx mis \u00e0 jour'); } catch(e){ err('StoryStudio: '+e.message); }
try { fs.writeFileSync(path.join(ROOT,'src/components/JejoStudio.jsx'), Buffer.from('','base64').toString('utf8'),'utf8'); good('JejoStudio.jsx mis \u00e0 jour'); } catch(e){ err('JejoStudio: '+e.message); }

// [2] Reels.jsx \u2014 bouton + rond en bas centre (sans texte)
console.log('\n[2] Reels.jsx \u2014 bouton +...');
rep('src/pages/Reels.jsx', `      <button onClick={() => setJejoStudio(true)} style={{ position:'absolute', top:12, right:14, zIndex:50, background:'linear-gradient(135deg,#FF2D8D,#FF7AB8)', border:'none', borderRadius:24, height:44, padding:'0 16px', display:'flex', alignItems:'center', gap:7, cursor:'pointer', color:'#fff', fontWeight:800, fontSize:14, boxShadow:'0 4px 16px rgba(255,45,141,.5)' }}>
        <svg width="20" height="20" viewBox="0 0 24 24" fill="none"><path d="M12 5v14M5 12h14" stroke="currentColor" strokeWidth="2.4" strokeLinecap="round"/></svg> Jejo
      </button>`, `      <button onClick={() => setJejoStudio(true)} aria-label="Créer un Jejo" style={{ position:'absolute', bottom:'calc(24px + env(safe-area-inset-bottom))', left:'50%', transform:'translateX(-50%)', zIndex:60, width:60, height:60, borderRadius:'50%', background:'linear-gradient(135deg,#FF2D8D,#FF7AB8)', border:'3px solid rgba(255,255,255,.9)', display:'flex', alignItems:'center', justifyContent:'center', cursor:'pointer', color:'#fff', boxShadow:'0 6px 20px rgba(255,45,141,.6)' }}>
        <svg width="30" height="30" viewBox="0 0 24 24" fill="none"><path d="M12 5v14M5 12h14" stroke="currentColor" strokeWidth="2.6" strokeLinecap="round"/></svg>
      </button>`, 'Bouton + rond bas-centre');
rep('src/pages/Reels.jsx', `<button onClick={() => setJejoStudio(true)} style={{ marginTop:8, background:'linear-gradient(135deg,#FF2D8D,#FF7AB8)', border:'none', borderRadius:24, height:46, padding:'0 22px', display:'flex', alignItems:'center', gap:8, cursor:'pointer', color:'#fff', fontWeight:800, fontSize:15 }}><svg width="20" height="20" viewBox="0 0 24 24" fill="none"><path d="M12 5v14M5 12h14" stroke="currentColor" strokeWidth="2.4" strokeLinecap="round"/></svg> Créer un Jejo</button>`, `<button onClick={() => setJejoStudio(true)} aria-label="Créer un Jejo" style={{ marginTop:12, width:64, height:64, borderRadius:'50%', background:'linear-gradient(135deg,#FF2D8D,#FF7AB8)', border:'none', display:'flex', alignItems:'center', justifyContent:'center', cursor:'pointer', color:'#fff', boxShadow:'0 6px 20px rgba(255,45,141,.5)' }}><svg width="32" height="32" viewBox="0 0 24 24" fill="none"><path d="M12 5v14M5 12h14" stroke="currentColor" strokeWidth="2.6" strokeLinecap="round"/></svg></button>`, 'Bouton + rond (\u00e9tat vide)');

console.log('\n\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550');
console.log('  Résultat: ' + ok + ' \u2705   ' + fail + ' \u274c');
console.log('\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550');
if (fail === 0) console.log('\n\ud83c\udf89 Termin\u00e9 ! npx vite build\n');
else console.log('\n\u26a0\ufe0f  Erreur(s) \u2014 envoie ce log.\n');
